// src/components/InternshipCard.jsx
import React from 'react';

export default function InternshipCard({
  internship,
  userRole,
  onApply,
  onEdit,
  onDelete,
  applied,
}) {
  return (
    <div className="border rounded-xl p-4 shadow-md bg-white">
      <h2 className="text-xl font-bold">{internship.title}</h2>
      <p className="text-gray-700">{internship.company}</p>
      <p>{internship.category} | {internship.location} | {internship.mode}</p>
      <p className="text-sm text-gray-500">{internship.description}</p>

      <div className="mt-3 flex gap-2">
        {userRole === 'Student' && (
          <button
            className={`px-4 py-1 rounded ${applied ? 'bg-gray-400' : 'bg-blue-600 text-white'}`}
            disabled={applied}
            onClick={() => onApply(internship._id)}
          >
            {applied ? 'Applied' : 'Apply'}
          </button>
        )}

        {(userRole === 'Admin' || userRole === 'HR') && (
          <>
            <button
              className="px-4 py-1 rounded bg-yellow-500 text-white"
              onClick={() => onEdit(internship)}
            >
              Edit
            </button>
            {userRole === 'Admin' && (
              <button
                className="px-4 py-1 rounded bg-red-500 text-white"
                onClick={() => onDelete(internship._id)}
              >
                Delete
              </button>
            )}
          </>
        )}
      </div>
    </div>
  );
}
